ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?project_manager ?construction_manager ?projectname WHERE {
  ?projects a :Projects .
  ?projects p:Project_Manager ?project_manager .
  ?projects p:Construction_Manager ?construction_manager .
  ?projects p:name ?projectname .
} }
  component: { SELECT ?project_manager ?projectname WHERE {
  ?projects a :Projects .
  ?projects p:Project_Manager ?project_manager .
  ?projects p:name ?projectname .
} }
  component_2: { SELECT ?construction_manager ?projectname WHERE {
  ?projects a :Projects .
  ?projects p:Construction_Manager ?construction_manager .
  ?projects p:name ?projectname .
} }
}

PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?project_manager ?construction_manager ?budget WHERE {
  ?projects a :Projects .
  ?projects p:Project_Manager ?project_manager .
  ?projects p:Construction_Manager ?construction_manager .
  ?projects p:budget ?budget .
  ?projects p:budget ?budget_o .
}
ORDER BY DESC(?budget_o)
LIMIT 1 }
  component: { SELECT ?construction_manager ?budget WHERE {
  ?projects a :Projects .
  ?projects p:Construction_Manager ?construction_manager .
  ?projects p:budget ?budget .
  ?projects p:budget ?budget_o .
}
ORDER BY DESC(?budget_o)
LIMIT 1 }
  component_2: { SELECT ?project_manager ?budget WHERE {
  ?projects a :Projects .
  ?projects p:Project_Manager ?project_manager .
  ?projects p:budget ?budget .
  ?projects p:budget ?budget_o .
}
ORDER BY DESC(?budget_o)
LIMIT 1 }
}
